import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Mail, Lock } from 'lucide-react';

const Login = ({ setIsLoggedIn, setUserRole }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    
    // Obtenemos la base de datos de usuarios simulada
    const usuariosDB = JSON.parse(localStorage.getItem('usuarios-db') || "[]");
    
    // Buscamos el usuario por email y password
    const usuario = usuariosDB.find(u => u.correo === email && u.password === password);

    if (usuario) {
      // Guardamos la sesión profesionalmente
      localStorage.setItem('token-falso', `token-${usuario.id}-${Date.now()}`);
      localStorage.setItem('user-role', usuario.rol);
      localStorage.setItem('user-id', usuario.id);
      localStorage.setItem('user-name', usuario.nombre);
      localStorage.setItem('user-username', usuario.nombreUsuario);
      
      setIsLoggedIn(true);
      setUserRole(usuario.rol);
      
      // Redirección según rol
      navigate(usuario.rol === 'vendedor' ? '/dashboard' : '/');
    } else {
      alert("Credenciales incorrectas. Verifique su correo y contraseña.");
    }
  };

  return (
    <div style={containerStyle}>
      <form onSubmit={handleLogin} style={formStyle}>
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <h2 style={{ fontSize: '2rem', color: '#1e293b', margin: 0 }}>Bienvenido</h2>
          <p style={{ color: '#64748b' }}>Ingresa a tu cuenta de OfertasAPP</p>
        </div>
        
        <div style={inputGroup}>
          <label style={labelStyle}>Correo Electrónico</label>
          <div style={inputWrapper}>
            <Mail size={18} color="#94a3b8" />
            <input 
              type="email" 
              placeholder="correo@ejemplo.com" 
              style={inputStyle} 
              required 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}>Contraseña</label>
          <div style={inputWrapper}>
            <Lock size={18} color="#94a3b8" />
            <input 
              type="password" 
              placeholder="••••••••" 
              style={inputStyle} 
              required 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
        </div>
        
        <button type="submit" style={btnSubmit}>Iniciar Sesión</button>

        <p style={{ textAlign: 'center', marginTop: '20px', color: '#64748b' }}>
          ¿No tienes cuenta? <Link to="/registro" style={{ color: '#e67e22', fontWeight: 'bold', textDecoration: 'none' }}>Regístrate aquí</Link>
        </p>
      </form>
    </div>
  );
};

const containerStyle = { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '85vh', background: '#f8fafc' };
const formStyle = { background: 'white', padding: '40px', borderRadius: '24px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', width: '100%', maxWidth: '400px' };
const inputGroup = { marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '8px', fontSize: '0.9rem', fontWeight: '600', color: '#475569' };
const inputWrapper = { display: 'flex', alignItems: 'center', gap: '10px', background: '#f1f5f9', padding: '0 15px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const inputStyle = { width: '100%', padding: '12px 0', border: 'none', background: 'transparent', outline: 'none', fontSize: '1rem' };
const btnSubmit = { width: '100%', padding: '14px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem', marginTop: '10px' };

export default Login;
